import React, { Component } from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Maintenance from './Pages/Maintenance';
import RouteToLink from './Utilities/RouteToLink';

class App extends Component {
  render() {
    return (
      <div id='App'>
        <Router>
          <Switch>
            <Route exact path='/instagram'>
              <RouteToLink link='https://www.instagram.com/ahmetcetinkaya.png' />
            </Route>
            <Route exact path='/twitter'>
              <RouteToLink link='https://twitter.com/ahmet4cetinkaya' />
            </Route>
            <Route exact path='/linkedin'>
              <RouteToLink link='https://www.linkedin.com/in/ahmet-cetinkaya' />
            </Route>
            <Route exact path='/github'>
              <RouteToLink link='https://github.com/ahmet-cetinkaya' />
            </Route>
            <Route exact path='/behance'>
              <RouteToLink link='https://www.behance.net/ahmetcetinkaya' />
            </Route>
            <Route path='/'>
              <Maintenance />
            </Route>
          </Switch>
        </Router>
      </div>
    );
  }
}

export default App;
